// `tauri ios init` seeds the Xcode asset catalog with a placeholder AppIcon.
// This copies Neoma's real iOS icons (generated by `tauri icon` into
// src-tauri/icons/ios/) over the top, so the app shows the leaf, not the
// default. Runs automatically after `npm run ios:init`; safe to re-run.
import { readdir, copyFile, access } from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const root = path.dirname(path.dirname(fileURLToPath(import.meta.url)))
const src = path.join(root, 'src-tauri', 'icons', 'ios')
const dest = path.join(root, 'src-tauri', 'gen', 'apple', 'Assets.xcassets', 'AppIcon.appiconset')

try {
  await access(dest)
} catch {
  console.log('sync-ios-icons: no iOS project yet (run `npm run ios:init` first) — skipping')
  process.exit(0)
}

const files = (await readdir(src)).filter((f) => f.endsWith('.png'))
for (const file of files) {
  await copyFile(path.join(src, file), path.join(dest, file))
}
console.log(`sync-ios-icons: copied ${files.length} Neoma icons into the iOS asset catalog`)
